private struct GrokChatScreen: View {
    @State private var draft = ""
    var body: some View {
        VStack(spacing: 0) {
            ScrollView {
                VStack(spacing: 12) {
                    ForEach(GrokDemoData.messages) { msg in
                        if msg.isUser { GrokUserBubble(text: msg.text, accent: GrokTokens.grokAccentWhite) }
                        else { GrokAssistantBubble(text: msg.text, surface: GrokTokens.grokSurface1) }
                    }
                }.padding()
            }.background(GrokTokens.grokCanvas.ignoresSafeArea())
            HStack(spacing: 12) {
                TextField("Message Grok…", text: $draft, axis: .vertical).padding(10).background(RoundedRectangle(cornerRadius: 20).fill(GrokTokens.grokSurface1))
                Button {} label: { Image(systemName: "arrow.up.circle.fill").font(.title2).foregroundStyle(GrokTokens.grokAccentWhite) }
            }.padding().background(.bar)
        }
    }
}

private struct GrokUserBubble: View {
    let text: String; let accent: Color
    var body: some View { HStack { Spacer(minLength: 48); Text(text).padding(12).background(RoundedRectangle(cornerRadius: 16).fill(accent.opacity(0.15))) } }
}

private struct GrokAssistantBubble: View {
    let text: String; let surface: Color
    var body: some View { HStack { Text(text).padding(12).background(RoundedRectangle(cornerRadius: 16).fill(surface)); Spacer(minLength: 48) } }
}

